package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"
)

// TestDefaultContextAuthenticatedData verifies that DefaultContext implements
// Context and returns itself from AuthenticatedData.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	data := []byte("authenticated-data")
	dc := DefaultContext(data)
	got := dc.AuthenticatedData()
	if !bytes.Equal(got, data) {
		t.Errorf("AuthenticatedData() = %q, want %q", got, data)
	}
}

// TestDefaultContextNil verifies that a nil DefaultContext returns nil from
// AuthenticatedData, not a panic.
func TestDefaultContextNil(t *testing.T) {
	var dc DefaultContext
	got := dc.AuthenticatedData()
	if got != nil {
		t.Errorf("AuthenticatedData() on nil DefaultContext = %q, want nil", got)
	}
}

// TestDefaultContextEmpty verifies that an empty DefaultContext returns an
// empty (non-nil) byte slice from AuthenticatedData.
func TestDefaultContextEmpty(t *testing.T) {
	dc := DefaultContext([]byte{})
	got := dc.AuthenticatedData()
	if got == nil {
		t.Errorf("AuthenticatedData() on empty DefaultContext = nil, want empty slice")
	}
	if len(got) != 0 {
		t.Errorf("AuthenticatedData() on empty DefaultContext len = %d, want 0", len(got))
	}
}

// TestTransformerRoundTrip verifies that a PrefixTransformer correctly encodes
// data to storage and decodes it back, preserving the original value.
func TestTransformerRoundTrip(t *testing.T) {
	original := []byte("hello-world")
	transformed := []byte("transformed-hello-world")
	inner := &testTransformer{
		from: original,
		to:   transformed,
	}
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: inner},
	)

	ctx := context.Background()

	// Write path: TransformToStorage should prepend the prefix.
	encoded, err := pt.TransformToStorage(ctx, original, nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}
	want := append([]byte("enc:"), transformed...)
	if !bytes.Equal(encoded, want) {
		t.Errorf("TransformToStorage() = %q, want %q", encoded, want)
	}

	// Read path: TransformFromStorage should strip the prefix and delegate.
	decoded, stale, err := pt.TransformFromStorage(ctx, encoded, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if stale {
		t.Errorf("TransformFromStorage() stale = true, want false for first transformer")
	}
	if !bytes.Equal(decoded, original) {
		t.Errorf("TransformFromStorage() = %q, want %q", decoded, original)
	}
}

// TestPrefixTransformerMismatch verifies that data with an unrecognized prefix
// returns the configured default error.
func TestPrefixTransformerMismatch(t *testing.T) {
	defaultErr := fmt.Errorf("no matching transformer")
	pt := NewPrefixTransformers(defaultErr,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("val")}},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("other:value"), nil)
	if err != defaultErr {
		t.Errorf("TransformFromStorage() with unknown prefix: err = %v, want %v", err, defaultErr)
	}
}

// TestPrefixTransformerStaleOnNonFirst verifies that data decoded by a
// non-first transformer is always marked stale to trigger a rewrite with
// the current (first) transformer.
func TestPrefixTransformerStaleOnNonFirst(t *testing.T) {
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("new:"), Transformer: &testTransformer{from: []byte("val")}},
		PrefixTransformer{Prefix: []byte("old:"), Transformer: &testTransformer{from: []byte("val")}},
	)

	_, stale, err := pt.TransformFromStorage(context.Background(), []byte("old:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !stale {
		t.Errorf("TransformFromStorage() stale = false, want true for non-first transformer match")
	}
}

// TestPrefixTransformerNotStaleOnFirst verifies that data decoded by the first
// transformer is not marked stale when the underlying transformer also is not stale.
func TestPrefixTransformerNotStaleOnFirst(t *testing.T) {
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("new:"), Transformer: &testTransformer{from: []byte("val"), stale: false}},
		PrefixTransformer{Prefix: []byte("old:"), Transformer: &testTransformer{from: []byte("val")}},
	)

	_, stale, err := pt.TransformFromStorage(context.Background(), []byte("new:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if stale {
		t.Errorf("TransformFromStorage() stale = true, want false for first transformer match")
	}
}

// TestPrefixTransformerInnerStalePreserved verifies that if the inner
// transformer reports stale=true on the first-position transformer, the stale
// flag is propagated to the caller.
func TestPrefixTransformerInnerStalePreserved(t *testing.T) {
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("val"), stale: true}},
	)

	_, stale, err := pt.TransformFromStorage(context.Background(), []byte("enc:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error: %v", err)
	}
	if !stale {
		t.Errorf("TransformFromStorage() stale = false, want true when inner transformer reports stale")
	}
}

// TestPrefixTransformerErrorPropagation verifies that errors from the
// underlying transformer during reads are surfaced to the caller.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	innerErr := fmt.Errorf("decryption failed")
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{err: innerErr}},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:data"), nil)
	if err == nil {
		t.Fatal("TransformFromStorage() expected error, got nil")
	}
}

// TestPrefixTransformerToStorageError verifies that errors from the underlying
// transformer during writes are propagated to the caller.
func TestPrefixTransformerToStorageError(t *testing.T) {
	innerErr := fmt.Errorf("encryption failed")
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{err: innerErr}},
	)

	_, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
	if err == nil {
		t.Fatal("TransformToStorage() expected error, got nil")
	}
	if err != innerErr {
		t.Errorf("TransformToStorage() err = %v, want %v", err, innerErr)
	}
}

// TestPrefixTransformerToStorageUsesFirstTransformer verifies that
// TransformToStorage always delegates to the first listed PrefixTransformer,
// regardless of how many transformers are configured.
func TestPrefixTransformerToStorageUsesFirstTransformer(t *testing.T) {
	first := &testTransformer{to: []byte("from-first")}
	second := &testTransformer{to: []byte("from-second")}
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("first:"), Transformer: first},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: second},
	)

	result, err := pt.TransformToStorage(context.Background(), []byte("input"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage() unexpected error: %v", err)
	}
	want := []byte("first:from-first")
	if !bytes.Equal(result, want) {
		t.Errorf("TransformToStorage() = %q, want %q", result, want)
	}
	if second.receivedTo != nil {
		t.Error("second transformer was invoked during TransformToStorage, should not have been")
	}
}

// TestPrefixTransformerPrefixStrippedBeforeInnerTransform verifies that the
// configured prefix is stripped from data before it is passed to the inner
// transformer's TransformFromStorage method.
func TestPrefixTransformerPrefixStrippedBeforeInnerTransform(t *testing.T) {
	inner := &testTransformer{from: []byte("decoded")}
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: inner},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:raw-data"), nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !bytes.Equal(inner.receivedFrom, []byte("raw-data")) {
		t.Errorf("inner transformer received %q, want %q (prefix must be stripped)", inner.receivedFrom, "raw-data")
	}
}

// TestPrefixTransformerEmptyValue verifies that empty input bytes can be
// transformed and decoded without error.
func TestPrefixTransformerEmptyValue(t *testing.T) {
	inner := &testTransformer{from: []byte{}, to: []byte{}}
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: inner},
	)

	ctx := context.Background()
	encoded, err := pt.TransformToStorage(ctx, []byte{}, nil)
	if err != nil {
		t.Fatalf("TransformToStorage() with empty value: %v", err)
	}

	// Output should be just the prefix since transformed value is empty.
	wantEncoded := []byte("enc:")
	if !bytes.Equal(encoded, wantEncoded) {
		t.Errorf("TransformToStorage() = %q, want %q", encoded, wantEncoded)
	}

	decoded, _, err := pt.TransformFromStorage(ctx, encoded, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() with prefix-only value: %v", err)
	}
	if !bytes.Equal(decoded, []byte{}) {
		t.Errorf("TransformFromStorage() = %q, want empty slice", decoded)
	}
}

// TestNewPrefixTransformersDefaultError verifies that passing nil as the error
// to NewPrefixTransformers results in a meaningful default error when no prefix
// matches, rather than a nil error (which would be ambiguous).
func TestNewPrefixTransformersDefaultError(t *testing.T) {
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("val")}},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("other:data"), nil)
	if err == nil {
		t.Fatal("expected non-nil error for unmatched prefix when nil error passed to NewPrefixTransformers")
	}
}

// TestPrefixTransformerIdentityPrefixFallthrough verifies the identity-prefix
// fallthrough: a transformer with an empty prefix matches everything, but if it
// returns an error, the next transformer in the list is tried instead.
func TestPrefixTransformerIdentityPrefixFallthrough(t *testing.T) {
	innerErr := fmt.Errorf("identity transformer error: data appears encrypted")
	// Identity transformer errors (e.g., detects encrypted data), then the real
	// transformer decrypts it successfully.
	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte{}, Transformer: &testTransformer{err: innerErr}},
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("decrypted")}},
	)

	got, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:ciphertext"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error after identity fallthrough: %v", err)
	}
	if !bytes.Equal(got, []byte("decrypted")) {
		t.Errorf("TransformFromStorage() = %q, want %q", got, "decrypted")
	}
}

// TestPrefixTransformerMultipleTransformers exercises TransformFromStorage with
// multiple PrefixTransformers using table-driven subtests covering the primary
// happy path and several failure/edge cases.
func TestPrefixTransformerMultipleTransformers(t *testing.T) {
	defaultErr := fmt.Errorf("default error: no matching prefix")
	transformErr := fmt.Errorf("transform error: bad key")

	tests := []struct {
		name         string
		input        []byte
		transformers []PrefixTransformer
		wantResult   []byte
		wantStale    bool
		wantErr      bool
	}{
		{
			name:  "first prefix matches, not stale",
			input: []byte("alpha:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("alpha:"), Transformer: &testTransformer{from: []byte("decoded-alpha")}},
				{Prefix: []byte("beta:"), Transformer: &testTransformer{from: []byte("decoded-beta")}},
			},
			wantResult: []byte("decoded-alpha"),
			wantStale:  false,
			wantErr:    false,
		},
		{
			name:  "second prefix matches, marked stale for rewrite",
			input: []byte("beta:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("alpha:"), Transformer: &testTransformer{from: []byte("decoded-alpha")}},
				{Prefix: []byte("beta:"), Transformer: &testTransformer{from: []byte("decoded-beta")}},
			},
			wantResult: []byte("decoded-beta"),
			wantStale:  true,
			wantErr:    false,
		},
		{
			name:  "no prefix matches, default error returned",
			input: []byte("gamma:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("alpha:"), Transformer: &testTransformer{from: []byte("decoded-alpha")}},
			},
			wantResult: nil,
			wantStale:  false,
			wantErr:    true,
		},
		{
			name:  "matching prefix but inner transformer errors",
			input: []byte("alpha:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("alpha:"), Transformer: &testTransformer{err: transformErr}},
			},
			wantResult: nil,
			wantStale:  false,
			wantErr:    true,
		},
		{
			name:  "third prefix matches after two misses, marked stale",
			input: []byte("gamma:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("alpha:"), Transformer: &testTransformer{from: []byte("decoded-alpha")}},
				{Prefix: []byte("beta:"), Transformer: &testTransformer{from: []byte("decoded-beta")}},
				{Prefix: []byte("gamma:"), Transformer: &testTransformer{from: []byte("decoded-gamma")}},
			},
			wantResult: []byte("decoded-gamma"),
			wantStale:  true,
			wantErr:    false,
		},
		{
			name:  "exact prefix match with similar longer prefix present",
			input: []byte("enc:v1:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("enc:v2:"), Transformer: &testTransformer{from: []byte("v2-decoded")}},
				{Prefix: []byte("enc:v1:"), Transformer: &testTransformer{from: []byte("v1-decoded")}},
			},
			wantResult: []byte("v1-decoded"),
			wantStale:  true,
			wantErr:    false,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(defaultErr, tc.transformers...)
			got, stale, err := pt.TransformFromStorage(context.Background(), tc.input, nil)
			if (err != nil) != tc.wantErr {
				t.Errorf("TransformFromStorage() err = %v, wantErr = %v", err, tc.wantErr)
			}
			if stale != tc.wantStale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.wantStale)
			}
			if !bytes.Equal(got, tc.wantResult) {
				t.Errorf("TransformFromStorage() = %q, want %q", got, tc.wantResult)
			}
		})
	}
}

// TestPrefixTransformerOverlappingPrefixKeyRotation verifies the key-rotation
// scenario described in transformer.go: two transformers share the same prefix
// (e.g., two AES-CBC configs with different keys). If the first fails, the
// second should be attempted and a successful match marked stale for rewrite.
func TestPrefixTransformerOverlappingPrefixKeyRotation(t *testing.T) {
	innerErr := fmt.Errorf("wrong key: cannot decrypt")
	pt := NewPrefixTransformers(nil,
		// New key (rotation target) — fails for data encrypted with old key.
		PrefixTransformer{Prefix: []byte("k8s:enc:aescbc:v1:"), Transformer: &testTransformer{err: innerErr}},
		// Old key (rotation source) — succeeds.
		PrefixTransformer{Prefix: []byte("k8s:enc:aescbc:v1:"), Transformer: &testTransformer{from: []byte("plaintext")}},
	)

	got, stale, err := pt.TransformFromStorage(context.Background(), []byte("k8s:enc:aescbc:v1:ciphertext"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error during key rotation: %v", err)
	}
	if !bytes.Equal(got, []byte("plaintext")) {
		t.Errorf("TransformFromStorage() = %q, want %q", got, "plaintext")
	}
	// Matched at index 1 (non-zero), so stale must be true to trigger rewrite with new key.
	if !stale {
		t.Errorf("TransformFromStorage() stale = false, want true for second transformer match (key rotation)")
	}
}

// TestPrefixTransformerToStoragePrefixPrepended verifies that TransformToStorage
// correctly prepends the first transformer's prefix to the inner output.
func TestPrefixTransformerToStoragePrefixPrepended(t *testing.T) {
	tests := []struct {
		name   string
		prefix []byte
		inner  []byte
		want   []byte
	}{
		{
			name:   "simple prefix",
			prefix: []byte("enc:"),
			inner:  []byte("ciphertext"),
			want:   []byte("enc:ciphertext"),
		},
		{
			name:   "multi-segment prefix",
			prefix: []byte("k8s:enc:aescbc:v1:"),
			inner:  []byte("abc"),
			want:   []byte("k8s:enc:aescbc:v1:abc"),
		},
		{
			name:   "empty inner result",
			prefix: []byte("enc:"),
			inner:  []byte{},
			want:   []byte("enc:"),
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(nil,
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: &testTransformer{to: tc.inner},
				},
			)
			got, err := pt.TransformToStorage(context.Background(), []byte("input"), nil)
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(got, tc.want) {
				t.Errorf("TransformToStorage() = %q, want %q", got, tc.want)
			}
		})
	}
}

// TestPrefixTransformerContextPassedThrough verifies that the context passed to
// TransformFromStorage and TransformToStorage is forwarded to the inner transformer.
func TestPrefixTransformerContextPassedThrough(t *testing.T) {
	type ctxKey struct{}
	sentinel := "sentinel-value"
	ctx := context.WithValue(context.Background(), ctxKey{}, sentinel)

	var capturedFromCtx, capturedToCtx context.Context
	inner := &captureContextTransformer{
		onFrom: func(c context.Context) { capturedFromCtx = c },
		onTo:   func(c context.Context) { capturedToCtx = c },
	}

	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: inner},
	)

	_, _, _ = pt.TransformFromStorage(ctx, []byte("enc:data"), nil)
	if capturedFromCtx == nil {
		t.Fatal("TransformFromStorage() did not call inner transformer")
	}
	if capturedFromCtx.Value(ctxKey{}) != sentinel {
		t.Errorf("TransformFromStorage() context value = %v, want %q", capturedFromCtx.Value(ctxKey{}), sentinel)
	}

	_, _ = pt.TransformToStorage(ctx, []byte("data"), nil)
	if capturedToCtx == nil {
		t.Fatal("TransformToStorage() did not call inner transformer")
	}
	if capturedToCtx.Value(ctxKey{}) != sentinel {
		t.Errorf("TransformToStorage() context value = %v, want %q", capturedToCtx.Value(ctxKey{}), sentinel)
	}
}

// captureContextTransformer is a Transformer implementation that captures the
// context it receives, used for verifying context propagation.
type captureContextTransformer struct {
	onFrom func(context.Context)
	onTo   func(context.Context)
}

func (c *captureContextTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if c.onFrom != nil {
		c.onFrom(ctx)
	}
	return data, false, nil
}

func (c *captureContextTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if c.onTo != nil {
		c.onTo(ctx)
	}
	return data, nil
}

