				{Prefix: []byte("enc:v2:"), Transformer: &testTransformer{from: []byte("v2-decoded")}},
				{Prefix: []byte("enc:v1:"), Transformer: &testTransformer{from: []byte("v1-decoded")}},
			},
			wantResult: []byte("v1-decoded"),
			wantStale:  true,
			wantErr:    false,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(defaultErr, tc.transformers...)
			got, stale, err := pt.TransformFromStorage(context.Background(), tc.input, nil)
			if (err != nil) != tc.wantErr {
				t.Errorf("TransformFromStorage() err = %v, wantErr = %v", err, tc.wantErr)
			}
			if stale != tc.wantStale {
				t.Errorf("TransformFromStorage() stale = %v, want %v", stale, tc.wantStale)
			}
			if !bytes.Equal(got, tc.wantResult) {
				t.Errorf("TransformFromStorage() = %q, want %q", got, tc.wantResult)
			}
		})
	}
}

// TestPrefixTransformerOverlappingPrefixKeyRotation verifies the key-rotation
// scenario described in transformer.go: two transformers share the same prefix
// (e.g., two AES-CBC configs with different keys). If the first fails, the
// second should be attempted and a successful match marked stale for rewrite.
func TestPrefixTransformerOverlappingPrefixKeyRotation(t *testing.T) {
	innerErr := fmt.Errorf("wrong key: cannot decrypt")
	pt := NewPrefixTransformers(nil,
		// New key (rotation target) — fails for data encrypted with old key.
		PrefixTransformer{Prefix: []byte("k8s:enc:aescbc:v1:"), Transformer: &testTransformer{err: innerErr}},
		// Old key (rotation source) — succeeds.
		PrefixTransformer{Prefix: []byte("k8s:enc:aescbc:v1:"), Transformer: &testTransformer{from: []byte("plaintext")}},
	)

	got, stale, err := pt.TransformFromStorage(context.Background(), []byte("k8s:enc:aescbc:v1:ciphertext"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() unexpected error during key rotation: %v", err)
	}
	if !bytes.Equal(got, []byte("plaintext")) {
		t.Errorf("TransformFromStorage() = %q, want %q", got, "plaintext")
	}
	// Matched at index 1 (non-zero), so stale must be true to trigger rewrite with new key.
	if !stale {
		t.Errorf("TransformFromStorage() stale = false, want true for second transformer match (key rotation)")
	}
}

// TestPrefixTransformerToStoragePrefixPrepended verifies that TransformToStorage
// correctly prepends the first transformer's prefix to the inner output.
func TestPrefixTransformerToStoragePrefixPrepended(t *testing.T) {
	tests := []struct {
		name   string
		prefix []byte
		inner  []byte
		want   []byte
	}{
		{
			name:   "simple prefix",
			prefix: []byte("enc:"),
			inner:  []byte("ciphertext"),
			want:   []byte("enc:ciphertext"),
		},
		{
			name:   "multi-segment prefix",
			prefix: []byte("k8s:enc:aescbc:v1:"),
			inner:  []byte("abc"),
			want:   []byte("k8s:enc:aescbc:v1:abc"),
		},
		{
			name:   "empty inner result",
			prefix: []byte("enc:"),
			inner:  []byte{},
			want:   []byte("enc:"),
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(nil,
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: &testTransformer{to: tc.inner},
				},
			)
			got, err := pt.TransformToStorage(context.Background(), []byte("input"), nil)
			if err != nil {
				t.Fatalf("TransformToStorage() unexpected error: %v", err)
			}
			if !bytes.Equal(got, tc.want) {
				t.Errorf("TransformToStorage() = %q, want %q", got, tc.want)
			}
		})
	}
}

// TestPrefixTransformerContextPassedThrough verifies that the context passed to
// TransformFromStorage and TransformToStorage is forwarded to the inner transformer.
func TestPrefixTransformerContextPassedThrough(t *testing.T) {
	type ctxKey struct{}
	sentinel := "sentinel-value"
	ctx := context.WithValue(context.Background(), ctxKey{}, sentinel)

	var capturedFromCtx, capturedToCtx context.Context
	inner := &captureContextTransformer{
		onFrom: func(c context.Context) { capturedFromCtx = c },
		onTo:   func(c context.Context) { capturedToCtx = c },
	}

	pt := NewPrefixTransformers(nil,
		PrefixTransformer{Prefix: []byte("enc:"), Transformer: inner},
	)

	_, _, _ = pt.TransformFromStorage(ctx, []byte("enc:data"), nil)
	if capturedFromCtx == nil {
		t.Fatal("TransformFromStorage() did not call inner transformer")
	}
	if capturedFromCtx.Value(ctxKey{}) != sentinel {
		t.Errorf("TransformFromStorage() context value = %v, want %q", capturedFromCtx.Value(ctxKey{}), sentinel)
	}

	_, _ = pt.TransformToStorage(ctx, []byte("data"), nil)
	if capturedToCtx == nil {
		t.Fatal("TransformToStorage() did not call inner transformer")
	}
	if capturedToCtx.Value(ctxKey{}) != sentinel {
		t.Errorf("TransformToStorage() context value = %v, want %q", capturedToCtx.Value(ctxKey{}), sentinel)
	}
}

// captureContextTransformer is a Transformer implementation that captures the
// context it receives, used for verifying context propagation.
type captureContextTransformer struct {
	onFrom func(context.Context)
	onTo   func(context.Context)
}

func (c *captureContextTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if c.onFrom != nil {
		c.onFrom(ctx)
	}
	return data, false, nil
}

func (c *captureContextTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if c.onTo != nil {
		c.onTo(ctx)
	}
	return data, nil
}
